// Pega o base64 do input
const base64Data = $json.body.message.data;

// Decodifica e transforma em objeto JSON
const decodedData = JSON.parse(Buffer.from(base64Data, 'base64').toString('utf8'));

// Retorna os dados para o próximo nó
return decodedData;

// Pega o output
let agent = $json.output;

// Se for string, converte para objeto
if (typeof agent === 'string') {
  agent = JSON.parse(agent);
}

// Retorna
return [{
  json: { 
    agent: agent 
  }
}];

// Pega os dados do item anterior
const inputData = $input.item.json;


// Converte para JSON string e depois para base64
const jsonString = JSON.stringify(inputData);
const base64Data = Buffer.from(jsonString).toString('base64');

// Retorna no formato que o Pub/Sub espera
return [
  {
    json: {
      messages: [
        {
          data: base64Data
        }
      ]
    }
  }
];
